count_lct(L) ->
    CountL = 0,
    CountLC = 0,
    CountLCT = 0,
    lists:foldl(fun
        (Char, {L, LC, LCT}) when Char =:= $L -> {L + 1, LC, LCT};
        (Char, {L, LC, LCT}) when Char =:= $C -> {L, LC + L, LCT};
        (Char, {L, LC, LCT}) when Char =:= $T -> {L, LC, LCT + LC};
        (_, Acc) -> Acc
    end, {CountL, CountLC, CountLCT}, L),
