solve(S) ->
    Original = count_lct(S),
    Max = lists:max([
        Original,
        try_insert($L, S),
        try_insert($C, S),
        try_insert($T, S)
    ]),
    Max.

count_lct(S) ->
    count_lct(S, 0, 0, 0).

count_lct(<<>>, L, C, _) -> L * C;
count_lct(<<$L, Rest/binary>>, L, C, T) -> count_lct(Rest, L + 1, C, T);
count_lct(<<$C, Rest/binary>>, L, C, T) -> count_lct(Rest, L, C + L, T);
count_lct(<<$T, Rest/binary>>, L, C, T) -> count_lct(Rest, L, C, T + C);
count_lct(<<_, Rest/binary>>, L, C, T) -> count_lct(Rest, L, C, T).

try_insert(Char, S) ->
    try_insert(Char, S, 0, 0, 0, 0).

try_insert(Char, <<>>, L, C, T, Max) ->
    NewL = if Char == $L -> L + 1; true -> L end,
    NewC = if Char == $C -> C + L; true -> C end,
    NewT = if Char == $T -> T + C; true -> T end,
    max(Max, NewL * NewC);
try_insert(Char, <<H, Rest/binary>>, L, C, T, Max) ->
    % Option to insert before H
    NewMax1 = if
        Char == $L -> max(Max, (L + 1) * C);
        Char == $C -> max(Max, L * (C + L));
        Char == $T -> max(Max, L * C)
    end,
    % Update counts based on current character H
    {NewL, NewC, NewT} = case H of
        $L -> {L + 1, C, T};
        $C -> {L, C + L, T};
        $T -> {L, C, T + C};
        _ -> {L, C, T}
    end,
    % Recurse
    NewMax2 = try_insert(Char, Rest, NewL, NewC, NewT, NewMax1),
    max(NewMax1, NewMax2).
